(function() {
  'use strict';

  // ==========================================
  // MENU MOBILE
  // ==========================================
  var toggle = document.getElementById('nav-toggle');
  var menu = document.getElementById('nav-menu');

  if (toggle && menu) {
    toggle.addEventListener('click', function() {
      var isOpen = menu.classList.toggle('active');
      toggle.setAttribute('aria-expanded', isOpen);
      // Animate hamburger
      var spans = toggle.querySelectorAll('span');
      if (isOpen) {
        spans[0].style.transform = 'rotate(45deg) translate(5px, 5px)';
        spans[1].style.opacity = '0';
        spans[2].style.transform = 'rotate(-45deg) translate(5px, -5px)';
      } else {
        spans[0].style.transform = '';
        spans[1].style.opacity = '';
        spans[2].style.transform = '';
      }
    });

    // Close menu on link click (mobile)
    var menuLinks = menu.querySelectorAll('a');
    for (var i = 0; i < menuLinks.length; i++) {
      menuLinks[i].addEventListener('click', function() {
        if (window.innerWidth <= 768) {
          menu.classList.remove('active');
          toggle.setAttribute('aria-expanded', 'false');
          var spans = toggle.querySelectorAll('span');
          spans[0].style.transform = '';
          spans[1].style.opacity = '';
          spans[2].style.transform = '';
        }
      });
    }
  }

  // ==========================================
  // TESTIMONIALS CAROUSEL
  // ==========================================
  var track = document.getElementById('testimonials-track');
  var dotsContainer = document.getElementById('carousel-dots');
  var prevBtn = document.getElementById('carousel-prev');
  var nextBtn = document.getElementById('carousel-next');

  if (track && dotsContainer) {
    var slides = track.querySelectorAll('.testimonial');
    var current = 0;
    var total = slides.length;
    var autoInterval;

    // Create dots
    for (var d = 0; d < total; d++) {
      var dot = document.createElement('button');
      dot.className = 'carousel-dot' + (d === 0 ? ' active' : '');
      dot.setAttribute('aria-label', 'Avis ' + (d + 1));
      dot.setAttribute('data-index', d);
      dot.addEventListener('click', function() {
        goTo(parseInt(this.getAttribute('data-index')));
      });
      dotsContainer.appendChild(dot);
    }

    function goTo(index) {
      current = index;
      if (current >= total) current = 0;
      if (current < 0) current = total - 1;
      track.style.transform = 'translateX(-' + (current * 100) + '%)';
      var dots = dotsContainer.querySelectorAll('.carousel-dot');
      for (var i = 0; i < dots.length; i++) {
        dots[i].classList.toggle('active', i === current);
      }
    }

    if (prevBtn) prevBtn.addEventListener('click', function() { goTo(current - 1); resetAuto(); });
    if (nextBtn) nextBtn.addEventListener('click', function() { goTo(current + 1); resetAuto(); });

    // Auto-play (cycle every 5s)
    function startAuto() {
      autoInterval = setInterval(function() { goTo(current + 1); }, 5000);
    }
    function resetAuto() {
      clearInterval(autoInterval);
      startAuto();
    }
    startAuto();

    // Pause on hover
    track.parentElement.addEventListener('mouseenter', function() { clearInterval(autoInterval); });
    track.parentElement.addEventListener('mouseleave', function() { startAuto(); });
  }

  // ==========================================
  // COOKIE BANNER
  // ==========================================
  var consent = localStorage.getItem('cookie-consent');
  var banner = document.getElementById('cookie-banner');
  var acceptBtn = document.getElementById('cookie-accept');
  var refuseBtn = document.getElementById('cookie-refuse');
  var manageBtn = document.getElementById('cookie-manage');

  if (!consent && banner) {
    banner.style.display = 'block';
  }

  if (consent === 'accepted') {
    loadAnalytics();
  }

  if (acceptBtn) {
    acceptBtn.addEventListener('click', function() {
      localStorage.setItem('cookie-consent', 'accepted');
      localStorage.setItem('cookie-consent-date', new Date().toISOString());
      if (banner) banner.style.display = 'none';
      loadAnalytics();
    });
  }

  if (refuseBtn) {
    refuseBtn.addEventListener('click', function() {
      localStorage.setItem('cookie-consent', 'refused');
      localStorage.setItem('cookie-consent-date', new Date().toISOString());
      if (banner) banner.style.display = 'none';
    });
  }

  if (manageBtn) {
    manageBtn.addEventListener('click', function(e) {
      e.preventDefault();
      localStorage.removeItem('cookie-consent');
      localStorage.removeItem('cookie-consent-date');
      if (banner) banner.style.display = 'block';
    });
  }

  function loadAnalytics() {
    // Google Analytics — remplacer UA-XXXXX par l'ID réel
    // if (!document.getElementById('ga-script')) {
    //   var s = document.createElement('script');
    //   s.id = 'ga-script';
    //   s.async = true;
    //   s.src = 'https://www.googletagmanager.com/gtag/js?id=G-XXXXXXX';
    //   document.head.appendChild(s);
    //   window.dataLayer = window.dataLayer || [];
    //   function gtag(){dataLayer.push(arguments);}
    //   gtag('js', new Date());
    //   gtag('config', 'G-XXXXXXX');
    // }
  }

  // ==========================================
  // GALLERY FILTERS (Réalisations)
  // ==========================================
  var filters = document.querySelectorAll('.gallery-filter');
  var items = document.querySelectorAll('.gallery-item');

  if (filters.length && items.length) {
    for (var f = 0; f < filters.length; f++) {
      filters[f].addEventListener('click', function() {
        // Remove active
        for (var j = 0; j < filters.length; j++) {
          filters[j].classList.remove('active');
        }
        this.classList.add('active');

        var cat = this.getAttribute('data-filter');
        for (var k = 0; k < items.length; k++) {
          if (cat === 'all' || items[k].getAttribute('data-cat') === cat) {
            items[k].style.display = '';
          } else {
            items[k].style.display = 'none';
          }
        }
      });
    }
  }

  // ==========================================
  // LIGHTBOX
  // ==========================================
  var lightbox = document.getElementById('lightbox');
  if (lightbox) {
    var lbImg = lightbox.querySelector('img');
    var lbCaption = lightbox.querySelector('.lightbox__caption');
    var lbClose = lightbox.querySelector('.lightbox__close');

    // Open on gallery item click
    var galleryItems = document.querySelectorAll('.gallery-item');
    for (var g = 0; g < galleryItems.length; g++) {
      galleryItems[g].addEventListener('click', function() {
        var img = this.querySelector('img');
        var caption = this.querySelector('.gallery-item__caption');
        if (img) {
          lbImg.src = img.src;
          lbImg.alt = img.alt;
        }
        if (caption && lbCaption) {
          lbCaption.textContent = caption.textContent;
        }
        lightbox.classList.add('active');
        document.body.style.overflow = 'hidden';
      });
    }

    // Close
    if (lbClose) {
      lbClose.addEventListener('click', closeLightbox);
    }
    lightbox.addEventListener('click', function(e) {
      if (e.target === lightbox) closeLightbox();
    });
    document.addEventListener('keydown', function(e) {
      if (e.key === 'Escape' && lightbox.classList.contains('active')) {
        closeLightbox();
      }
    });

    function closeLightbox() {
      lightbox.classList.remove('active');
      document.body.style.overflow = '';
      lbImg.src = '';
    }
  }

  // ==========================================
  // GOOGLE MAPS (conditional load)
  // ==========================================
  var loadMapBtn = document.getElementById('load-map');
  if (loadMapBtn) {
    loadMapBtn.addEventListener('click', function() {
      var container = document.getElementById('map-container');
      if (container) {
        container.innerHTML = '<iframe src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d2873.5!2d5.7869!3d43.8349!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x0%3A0x0!2sABC+Chape+liquide+%26+Carrelage!5e0!3m2!1sfr!2sfr!4v1" width="100%" height="400" style="border:0;border-radius:6px;" allowfullscreen loading="lazy" referrerpolicy="no-referrer-when-downgrade" title="ABC Chape liquide et Carrelage à Manosque"></iframe>';
      }
    });
  }

  // ==========================================
  // FORMS — CSRF + AJAX submit + status from URL
  // ==========================================

  // Generate CSRF token
  function generateCSRF() {
    var arr = new Uint8Array(32);
    crypto.getRandomValues(arr);
    return Array.from(arr, function(b) { return b.toString(16).padStart(2, '0'); }).join('');
  }

  // Set CSRF on forms
  var csrfFields = document.querySelectorAll('[name="csrf_token"]');
  if (csrfFields.length) {
    var token = generateCSRF();
    for (var c = 0; c < csrfFields.length; c++) {
      csrfFields[c].value = token;
    }
    // Store in session (for PHP to validate — note: for static-only, skip CSRF server-side)
  }

  // AJAX form submission
  var forms = document.querySelectorAll('#contact-form, #devis-form');
  for (var fi = 0; fi < forms.length; fi++) {
    forms[fi].addEventListener('submit', function(e) {
      e.preventDefault();
      var form = this;
      var msgEl = form.querySelector('.form__message') || document.getElementById('form-message') || document.getElementById('form-message-devis');
      var submitBtn = form.querySelector('button[type="submit"]');

      // Honeypot check
      var hp = form.querySelector('[name="website"]');
      if (hp && hp.value) return;

      if (submitBtn) {
        submitBtn.disabled = true;
        submitBtn.textContent = 'Envoi en cours...';
      }

      var data = new FormData(form);

      var xhr = new XMLHttpRequest();
      xhr.open('POST', form.action, true);
      xhr.setRequestHeader('X-Requested-With', 'XMLHttpRequest');
      xhr.onload = function() {
        if (submitBtn) {
          submitBtn.disabled = false;
          submitBtn.textContent = form.id === 'devis-form' ? 'Envoyer ma demande de devis' : 'Envoyer mon message';
        }
        try {
          var resp = JSON.parse(xhr.responseText);
          if (msgEl) {
            msgEl.textContent = resp.message;
            msgEl.className = 'form__message ' + (resp.success ? 'form__message--success' : 'form__message--error');
            msgEl.style.display = 'block';
          }
          if (resp.success) form.reset();
        } catch(err) {
          if (msgEl) {
            msgEl.textContent = 'Votre demande a bien été envoyée.';
            msgEl.className = 'form__message form__message--success';
            msgEl.style.display = 'block';
            form.reset();
          }
        }
      };
      xhr.onerror = function() {
        if (submitBtn) {
          submitBtn.disabled = false;
          submitBtn.textContent = form.id === 'devis-form' ? 'Envoyer ma demande de devis' : 'Envoyer mon message';
        }
        if (msgEl) {
          msgEl.textContent = 'Erreur de connexion. Appelez-nous au 06 52 25 12 26.';
          msgEl.className = 'form__message form__message--error';
          msgEl.style.display = 'block';
        }
      };
      xhr.send(data);
    });
  }

  // Check URL params for form status (non-JS fallback)
  var urlParams = new URLSearchParams(window.location.search);
  var statut = urlParams.get('statut');
  if (statut) {
    var msgTarget = document.querySelector('.form__message');
    if (msgTarget) {
      if (statut === 'ok') {
        msgTarget.textContent = 'Votre demande a bien été envoyée. Nous vous répondons sous 48h.';
        msgTarget.className = 'form__message form__message--success';
        msgTarget.style.display = 'block';
      } else if (statut === 'error') {
        msgTarget.textContent = 'Une erreur est survenue. Appelez-nous au 06 52 25 12 26.';
        msgTarget.className = 'form__message form__message--error';
        msgTarget.style.display = 'block';
      }
    }
  }

  // ==========================================
  // RELATED ARTICLES (blog pages)
  // ==========================================
  var relatedContainer = document.querySelector('[data-related]');
  if (relatedContainer) {
    var path = window.location.pathname;
    var currentSlug = path.split('/').pop();
    // Fix clean URLs
    if (currentSlug && currentSlug.indexOf('.html') === -1) currentSlug += '.html';

    var jsonPath = 'articles.json';
    // Determine relative path based on current location
    if (path.indexOf('/blog/') === -1) {
      jsonPath = 'blog/articles.json';
    }

    fetch(jsonPath)
      .then(function(r) { return r.json(); })
      .then(function(articles) {
        // Filter out current article
        var others = articles.filter(function(a) { return a.slug !== currentSlug; });

        // Fisher-Yates shuffle
        for (var i = others.length - 1; i > 0; i--) {
          var j = Math.floor(Math.random() * (i + 1));
          var temp = others[i];
          others[i] = others[j];
          others[j] = temp;
        }

        // Pick 2 random articles
        var picked = others.slice(0, 2);

        if (picked.length > 0) {
          var html = '';
          var basePath = path.indexOf('/blog/') !== -1 ? '' : 'blog/';
          for (var p = 0; p < picked.length; p++) {
            html += '<a href="' + basePath + picked[p].slug + '" class="blog-card">';
            html += '<div class="blog-card__body">';
            html += '<span class="blog-card__tag">' + picked[p].tag + '</span>';
            html += '<p class="blog-card__title">' + picked[p].title + '</p>';
            html += '<p class="blog-card__excerpt">' + picked[p].desc + '</p>';
            html += '<p class="blog-card__meta">' + picked[p].date + ' · ' + picked[p].readTime + '</p>';
            html += '</div></a>';
          }
          // 3rd card = services
          html += '<a href="' + (path.indexOf('/blog/') !== -1 ? '../' : '') + 'devis-en-ligne.html" class="blog-card" style="background:var(--accent-light);">';
          html += '<div class="blog-card__body" style="justify-content:center;text-align:center;">';
          html += '<p class="blog-card__title" style="color:var(--accent);">Un projet ? Demandez votre devis gratuit</p>';
          html += '<p class="blog-card__excerpt">Chape liquide, carrelage, parquet, rénovation. Réponse sous 48h.</p>';
          html += '</div></a>';

          relatedContainer.innerHTML = html;
        }
      })
      .catch(function() {
        // Keep static fallback
      });
  }

})();
